const parsePrimitives = (contents) => {
    // tokens.json uses 'primitives' as the reference name v.s. 'color primitives'
    const cleaned = contents.replace(/color primitives/g, 'primitives');
    return JSON.parse(cleaned);
};
const parseTokens = (contents) => {
    // primitives doesn't use modes, we just want the color alias
    const withoutModes = contents
        .replace(/(color primitives|primitives|color)\.(light|dark|hex|alt)\./g, 'primitives.')
        .replace(/integer\.(normal|dimension)\./g, 'integer.')
        // Fix typography references by removing mode 1
        .replace(/typography\.mode 1\./g, 'typography.');
    // remove dag for now
    const tokens = JSON.parse(withoutModes);
    delete tokens.color.light.dag;
    delete tokens.color.dark.dag;
    // ignore transparent
    delete tokens.color.light.focus.transparent;
    delete tokens.color.dark.focus.transparent;
    return tokens;
};
/**
 * there are some oddities about what the figma exports like how the variables are named
 * e.g. primitives v.s. color primitives
 * this attempts to smooth those out
 */
export const parseAssets = ({ filePath = '', contents = '' }) => {
    if (filePath.includes('tokens.json')) {
        return parseTokens(contents);
    }
    return parsePrimitives(contents);
};
